import base64
import pathlib

# 仅 Base64 段，不含中文
RAW = r""""""

b = RAW.strip().replace("\n", "")
canon = base64.b64encode(base64.b64decode(b)).decode("ascii")
out = pathlib.Path(__file__).parent / "app_private_key_upload.pem"
out.write_text(canon + "\n", encoding="utf-8", newline="\n")
print(canon, len(canon), file=__import__("sys").stderr, flush=True)
print("wrote", out, "b64 len", len(canon))
